import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        // Read entire input as a single string to handle both real newlines and literal "\\n" sequences
        InputStream in = System.in;
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        byte[] buffer = new byte[1 << 16];
        int read;
        while ((read = in.read(buffer)) != -1) {
            baos.write(buffer, 0, read);
        }
        String data = baos.toString().trim();
        // Replace literal "\\n" (backslash followed by n) with a space so they act as delimiters
        data = data.replace("\\n", " ");
        StringTokenizer st = new StringTokenizer(data);
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(st.nextToken());
            long X = Long.parseLong(st.nextToken());
            int ans = 0;
            for (int i = 1; i <= N; i++) {
                long a = Long.parseLong(st.nextToken());
                if (a < X) {
                    ans = i; // the farthest index where defence < X
                }
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

